import bisect

def f(lst):
    """Return the length of the longest strictly increasing subsequence of lst."""
    tails = []                     # tails[i] = smallest possible tail of an increasing subseq of length i+1
    for x in lst:
        # find the position to replace (first element >= x)
        i = bisect.bisect_left(tails, x)
        if i == len(tails):
            tails.append(x)        # extend the longest subsequence
        else:
            tails[i] = x           # improve the tail for length i+1
    return len(tails)
